    assert "QL_STEAM_SERVER_BROWSER_DETAIL_PLAYERS, QL_STEAM_SERVER_BROWSER_DETAIL_RESPONSE" in build_player_block
    assert "CL_SteamBrowser_PublishNativeRuleResponse( &response );" in native_rule_responded_block
